{"code": "import json

# Load civic documents from file path
civic_docs_file = locals()['var_functions.query_db:2']
with open(civic_docs_file, 'r') as f:
    civic_docs = json.load(f)

# Funding results are already loaded as a list
funding_results = locals()['var_functions.query_db:28']

print('Loaded %d civic documents and %d funding records' % (len(civic_docs), len(funding_results)))

# Extract project statuses from civic documents
status_map = {}

for doc in civic_docs:
    text = doc.get('text', '')
    lower_text = text.lower()

    # Look for completed projects
    if 'construction was completed' in lower_text:
        lines = text.split('\n')
        for i, line in enumerate(lines):
            if 'construction was completed' in line.lower():
                # Look backwards for project name
                for j in range(max(0, i-10), i):
                    prev_line = lines[j].strip()
                    if prev_line and not prev_line[0] in ['(', '•', '-', '◦']:
                        if any(k in prev_line.lower() for k in ['project', 'improvements', 'repairs']):
                            status_map[prev_line.lower()] = 'completed'

    # Look for design phase projects
    if 'complete design' in lower_text or 'finalize design' in lower_text:
        lines = text.split('\n')
        for i, line in enumerate(lines):
            if 'complete design' in line.lower() or 'finalize design' in line.lower():
                # Look backwards for project name
                for j in range(max(0, i-10), i):
                    prev_line = lines[j].strip()
                    if prev_line and not prev_line[0] in ['(', '•', '-', '◦']:
                        if any(k in prev_line.lower() for k in ['project', 'improvements', 'repairs', 'drainage']):
                            status_map[prev_line.lower()] = 'design'

print('Found %d project status mappings' % len(status_map))

# Match funding records with statuses
results = []

for rec in funding_results:
    name = rec['Project_Name']
    amount = int(rec['Amount'])
    source = rec['Funding_Source']

    # Create key for lookup (clean version)
    name_lower = name.lower()
    status = 'Unknown'

    # Direct lookup
    if name_lower in status_map:
        status = status_map[name_lower]
    else:
        # Try partial matches
        for key in status_map.keys():
            if name_lower.replace(' (fema project)', '') in key:
                status = status_map[key]
                break

    results.append({
        'Project_Name': name,
        'Funding_Source': source,
        'Amount': amount,
        'Status': status,
        'Type': 'disaster'
    })

# Sort by amount descending
results.sort(key=lambda x: x['Amount'], reverse=True)

# Format output nicely
print('SUMMARY OF PROJECTS RELATED TO EMERGENCY/FEMA:')
print('=' * 80)
for proj in results:
    print('Project: %s' % proj['Project_Name'])
    print('  Funding: $%d from %s' % (proj['Amount'], proj['Funding_Source']))
    print('  Status: %s' % proj['Status'])
    print('  Type: %s' % proj['Type'])
    print('-' * 60)

import json as js
print('__RESULT__:')
print(js.dumps(results))"}
